     1→/**
     2→ * ClassificationResult entity with explainability
     3→ *
     4→ * Core classification result with preserved sophistication and enhanced
     5→ * explainability for the 9-stage classification pipeline.
     6→ */
     7→
     8→import { ExplainabilityTrace } from './explainability-trace';
     9→import { ScoreBreakdown } from './score-breakdown';
    10→import { AttributeContext } from './attribute-context';
    11→
    12→/**
    13→ * Intermediate types for multi-label selection and AI routing stages
    14→ */
    15→
    16→export interface SelectedLabel {
    17→  category: string;
    18→  subtype: string | null;
    19→  confidence: number;
    20→  score: number;
    21→  isPrimary: boolean;
    22→  labelOrder: number;
    23→  selectionRationale: string;
    24→}
    25→
    26→/**
    27→ * Pipeline-oriented selection summary
    28→ * Used during pipeline execution and by persistence layer
    29→ */
    30→export interface PipelineSelectionSummary {
    31→  totalLabels: number;
    32→  primaryCategory: string | null;
    33→  confidenceRange: [number, number];
    34→  selectionMethod: string;
    35→  needsAi: boolean;
    36→  topCategories?: Array<{ category: string; score: number }>;
    37→}
    38→
    39→/**
    40→ * Final classification summary - consistent output regardless of AI path
    41→ * Generated in Action Determination stage (S9) after all classification stages complete
    42→ * Provides unified interface for downstream consumers (digest generation, analytics, etc)
    43→ */
    44→export interface FinalClassificationSummary {
    45→  totalLabels: number;
    46→  primaryCategory: string;
    47→  primarySubtype: string | null;
    48→  confidenceRange: [number, number];
    49→  classificationPath: 'ruleBased' | 'aiEnhanced';
    50→  selectedLabels: SelectedLabel[]; // Final state after all stages (including AI if applicable)
    51→  determinedActions: string[];
    52→  processingDurationMs: number;
    53→}
    54→
    55→export interface CandidateScore {
    56→  score: number;
    57→  confidence: number;
    58→  rationale?: string;
    59→  decision?: 'selected' | 'candidate' | 'rejected';
    60→  hardAssertion?: boolean;
    61→}
    62→
    63→export interface ClassificationResult {
    64→  id: string; // UUID
    65→  emailId: string; // Foreign key to EmailMessage
    66→  sessionId: string; // Foreign key to ClassificationSession
    67→
