      mockGmailClient.fetchEmails.mockResolvedValue([]);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processBatch({ maxEmails: 10 });

      expect(result.totalProcessed).toBe(0);
      expect(result.successCount).toBe(0);
      expect(result.errorCount).toBe(0);
      expect(mockClassificationOrchestrator.classifyBatch).not.toHaveBeenCalled();
      expect(mockPersistence.saveClassificationBatch).not.toHaveBeenCalled();
    });
  });

  describe('Single Email Processing', () => {
    test('should process single email successfully', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');
      const mockClassificationResult = createMockClassificationResult('msg1', 0.85);

      mockGmailClient.fetchEmailById.mockResolvedValue(mockEmail);
      mockClassificationOrchestrator.classify.mockResolvedValue(mockClassificationResult);
      mockPersistence.saveClassificationResult.mockResolvedValue(undefined);

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(true);
      expect(result.emailId).toBe('msg1');
      expect(result.classificationResult).toEqual(mockClassificationResult);
      expect(mockGmailClient.fetchEmailById).toHaveBeenCalledWith('msg1');
      expect(mockClassificationOrchestrator.classify).toHaveBeenCalledWith(mockEmail);
      expect(mockPersistence.saveClassificationResult).toHaveBeenCalledWith('msg1', mockClassificationResult);
    });

    test('should handle classification error for single email', async () => {
      const mockEmail = createMockEmail('msg1', 'Test Subject');

      mockGmailClient.fetchEmailById.mockResolvedValue(mockEmail);
      mockClassificationOrchestrator.classify.mockRejectedValue(new Error('Classification failed'));

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(false);
      expect(result.emailId).toBe('msg1');
      expect(result.error).toBeDefined();
      expect(result.error?.message).toBe('Classification failed');
      expect(mockPersistence.saveClassificationResult).not.toHaveBeenCalled();
    });

    test('should handle email not found error', async () => {
      mockGmailClient.fetchEmailById.mockRejectedValue(new Error('Email not found'));

      const processor = new EmailProcessor(
        mockGmailClient as unknown as GmailClient,
        mockClassificationOrchestrator as unknown as ClassificationOrchestrator,
        mockPersistence as unknown as PersistenceService,
        testConfig
      );

      const result = await processor.processSingle('msg1');

      expect(result.success).toBe(false);
      expect(result.emailId).toBe('msg1');
      expect(result.error?.message).toBe('Email not found');
    });
  });

  describe('Performance Metrics', () => {
    test('should track processing duration accurately', async () => {
      const mockEmails: EmailMessage[] = [
        createMockEmail('msg1', 'Test Subject 1'),
        createMockEmail('msg2', 'Test Subject 2'),
      ];

      const mockClassificationResults: ClassificationResult[] = [
        createMockClassificationResult('msg1', 0.85),
        createMockClassificationResult('msg2', 0.9),
