 *
 * Purpose: Validate that the system maintains the 6 core email categories required by FR-003:
 * 1. Receipts → financial category with receipt-related subtypes
 * 2. Shipping notifications → commerceLogistics category with shipping subtypes
 * 3. Newsletters → subscriptionContent category with newsletter subtypes
 * 4. Action items → actionable category
 * 5. Financial statements → financial category with statement subtypes
 * 6. Family communications → personal category with family subtypes
 *
 * These tests validate the configuration defines these categories and their required structure.
 */

import { ProcessingConfigTuningSchema } from '../../src/config/processing-config-schema';
import * as fs from 'fs';
import * as path from 'path';

describe('FR-003: Category Validation', () => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let config: any;
  let domainSourcesPath: string;

  beforeAll(() => {
    // Load the actual email-categorizer-config.json from the project
    const configPath = path.join(__dirname, '../../../../config/email-categorizer-config.json');
    domainSourcesPath = path.join(__dirname, '../../../../config/domain-sources.json');

    const configContent = fs.readFileSync(configPath, 'utf-8');
    const parsed = JSON.parse(configContent);
    config = parsed.processingConfig;
  });

  describe('FR-003: Core Categories Presence', () => {
    test('should have financial category for receipts and financial statements (FR-003 #1, #5)', () => {
      expect(config.topLevelCategories).toHaveProperty('financial');

      const financial = config.topLevelCategories.financial;
      expect(financial).toBeDefined();
      expect(financial.subtypes).toBeDefined();

      // Validate financial has receipt and statement subtypes
      const subtypeNames = Object.keys(financial.subtypes);
      expect(subtypeNames.length).toBeGreaterThan(0);
    });

    test('should have commerceLogistics category for shipping notifications (FR-003 #2)', () => {
      expect(config.topLevelCategories).toHaveProperty('commerceLogistics');

      const commerceLogistics = config.topLevelCategories.commerceLogistics;
      expect(commerceLogistics).toBeDefined();
      expect(commerceLogistics.subtypes).toBeDefined();

      // Validate has shipping-related subtypes
      const subtypeNames = Object.keys(commerceLogistics.subtypes);
      expect(subtypeNames.length).toBeGreaterThan(0);
    });

    test('should have subscriptionContent category for newsletters (FR-003 #3)', () => {
      expect(config.topLevelCategories).toHaveProperty('subscriptionContent');

      const subscriptionContent = config.topLevelCategories.subscriptionContent;
      expect(subscriptionContent).toBeDefined();
      expect(subscriptionContent.subtypes).toBeDefined();

      // Validate has newsletter subtypes
      const subtypeNames = Object.keys(subscriptionContent.subtypes);
      expect(subtypeNames.length).toBeGreaterThan(0);
    });

    test('should have actionable category for action items (FR-003 #4)', () => {
      expect(config.topLevelCategories).toHaveProperty('actionable');

      const actionable = config.topLevelCategories.actionable;
      expect(actionable).toBeDefined();
      expect(actionable.subtypes).toBeDefined();
    });

    test('should have personal category for family communications (FR-003 #6)', () => {
      expect(config.topLevelCategories).toHaveProperty('personal');

      const personal = config.topLevelCategories.personal;
      expect(personal).toBeDefined();
      expect(personal.subtypes).toBeDefined();

      // Validate has family-related subtypes
      const subtypeNames = Object.keys(personal.subtypes);
      expect(subtypeNames.length).toBeGreaterThan(0);
    });
  });

  describe('Category Configuration Structure', () => {
    test('should have valid structure for all top-level categories', () => {
      const topLevelCategories = config.topLevelCategories;
      expect(topLevelCategories).toBeDefined();

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      Object.entries(topLevelCategories).forEach(([_categoryName, categoryConfig]: [string, any]) => {
        // Each category should have subtypes
        expect(categoryConfig).toHaveProperty('subtypes');
        expect(typeof categoryConfig.subtypes).toBe('object');
      });
    });

    test('should pass Zod schema validation for overall processing config', () => {
      const result = ProcessingConfigTuningSchema.safeParse(config);

      expect(result.success).toBe(true);

      if (!result.success) {
        console.error('Processing config validation errors:', result.error.format());
      }
    });
  });

  describe('Domain Sources Integration', () => {
    test('should have domain sources file for category-based domain detection', () => {
      expect(fs.existsSync(domainSourcesPath)).toBe(true);

      const domainSources = JSON.parse(fs.readFileSync(domainSourcesPath, 'utf-8'));
      expect(domainSources).toBeDefined();
      expect(typeof domainSources).toBe('object');
      expect(Object.keys(domainSources).length).toBeGreaterThan(0);
    });
  });

  describe('Attribute System', () => {
    test('should have attribute detection system for cross-cutting signals', () => {
      expect(config.attributes).toBeDefined();
      expect(config.attributes.detectors).toBeDefined();
      expect(config.attributes.attributeBonusMap).toBeDefined();
    });

    test('should have actionable attribute for action item detection', () => {
      expect(config.attributes.attributeBonusMap).toHaveProperty('actionable');

      const actionable = config.attributes.attributeBonusMap.actionable;
      expect(actionable).toBeDefined();
      expect(typeof actionable).toBe('object');
    });
  });

  describe('Configuration Integrity', () => {
    test('should have all 6 FR-003 category capabilities defined', () => {
      /**
       * FR-003 requires support for:
       * 1. Receipts → financial category ✓
       * 2. Shipping notifications → commerceLogistics category ✓
       * 3. Newsletters → subscriptionContent category ✓
       * 4. Action items → actionable category ✓
       * 5. Financial statements → financial category (same as #1) ✓
       * 6. Family communications → personal category ✓
       */

      const topLevelCategories = config.topLevelCategories;

      // 1 & 5. Receipts and Financial statements capability
      expect(topLevelCategories).toHaveProperty('financial');

      // 2. Shipping notifications capability
      expect(topLevelCategories).toHaveProperty('commerceLogistics');

      // 3. Newsletters capability
      expect(topLevelCategories).toHaveProperty('subscriptionContent');

      // 4. Action items capability
      expect(topLevelCategories).toHaveProperty('actionable');

      // 6. Family communications capability
      expect(topLevelCategories).toHaveProperty('personal');
    });

    test('should have complete category taxonomy with subtypes', () => {
      const topLevelCategories = config.topLevelCategories;

      // FR-003 categories should have subtypes defined
      const fr003Categories = ['financial', 'commerceLogistics', 'subscriptionContent', 'actionable', 'personal'];

      fr003Categories.forEach((categoryName) => {
        expect(topLevelCategories[categoryName]).toBeDefined();
        expect(topLevelCategories[categoryName].subtypes).toBeDefined();
        expect(typeof topLevelCategories[categoryName].subtypes).toBe('object');
      });
    });
  });
});

