  describe('authentication status', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should return authentication status with valid tokens', async () => {
      const mockTokens = {
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      await gmailClient.setTokens(mockTokens);

      const mockProfile = {
        emailAddress: 'test@example.com',
      };

      mockGmailApi.users.getProfile = jest.fn().mockResolvedValue({
        data: mockProfile,
