        userId: 'me',
        id: threadId,
        format: 'full',
      });
      expect(thread).toEqual(mockThread);
      expect(thread.messages).toHaveLength(2);
    });

    it('should fetch thread with metadata format', async () => {
      const threadId = 'thread-456';
      const mockThread = {
        id: threadId,
        messages: [
          {
            id: 'msg-1',
            threadId: threadId,
            labelIds: ['INBOX'],
          },
        ],
      };

      mockGmailApi.users.threads.get = jest.fn().mockResolvedValue({
        data: mockThread,
      });

      const thread = await gmailClient.getThread(threadId, 'metadata');

      expect(mockGmailApi.users.threads.get).toHaveBeenCalledWith({
        userId: 'me',
        id: threadId,
        format: 'metadata',
