        { id: 'INBOX', name: 'INBOX', type: 'system' },
        { id: 'SENT', name: 'SENT', type: 'system' },
        { id: 'Label_1', name: 'Work', type: 'user' },
        { id: 'Label_2', name: 'Personal', type: 'user' },
      ];

      mockGmailApi.users.labels.list = jest.fn().mockResolvedValue({
        data: { labels: mockLabels },
      });

      const labels = await gmailClient.listLabels();

      expect(mockGmailApi.users.labels.list).toHaveBeenCalledWith({
        userId: 'me',
      });
      expect(labels).toEqual(mockLabels);
      expect(labels).toHaveLength(4);
    });

    it('should handle empty labels list', async () => {
      mockGmailApi.users.labels.list = jest.fn().mockResolvedValue({
        data: {},
      });

      const labels = await gmailClient.listLabels();

      expect(labels).toEqual([]);
    });

    it('should get specific label by ID', async () => {
      const labelId = 'Label_1';
      const mockLabel = {
        id: labelId,
        name: 'Work',
        type: 'user',
        messageListVisibility: 'show',
        labelListVisibility: 'labelShow',
      };

      mockGmailApi.users.labels.get = jest.fn().mockResolvedValue({
        data: mockLabel,
      });

      const label = await gmailClient.getLabel(labelId);

      expect(mockGmailApi.users.labels.get).toHaveBeenCalledWith({
        userId: 'me',
        id: labelId,
      });
      expect(label).toEqual(mockLabel);
    });

    it('should handle label not found errors', async () => {
      const labelId = 'non-existent-label';
      const notFoundError = {
        code: 404,
        message: 'Label not found',
      };

      mockGmailApi.users.labels.get = jest.fn().mockRejectedValue(notFoundError);

      await expect(gmailClient.getLabel(labelId)).rejects.toMatchObject({
        code: 404,
        message: 'Label not found',
      });
    });

    it('should retry on rate limits when listing labels', async () => {
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
      };
      const mockLabels = [{ id: 'INBOX', name: 'INBOX', type: 'system' }];

      // First call fails with rate limit, second succeeds
      mockGmailApi.users.labels.list = jest
        .fn()
        .mockRejectedValueOnce(rateLimitError)
        .mockResolvedValueOnce({ data: { labels: mockLabels } });

      const labels = await gmailClient.listLabels({ retryOnRateLimit: true, maxRetries: 3 });

      expect(labels).toEqual(mockLabels);
      expect(mockGmailApi.users.labels.list).toHaveBeenCalledTimes(2);
    });

    it('should retry on rate limits when getting label', async () => {
      const labelId = 'Label_1';
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
      };
      const mockLabel = { id: labelId, name: 'Work', type: 'user' };

      // First call fails with rate limit, second succeeds
      mockGmailApi.users.labels.get = jest
        .fn()
        .mockRejectedValueOnce(rateLimitError)
        .mockResolvedValueOnce({ data: mockLabel });

      const label = await gmailClient.getLabel(labelId, { retryOnRateLimit: true, maxRetries: 3 });

      expect(label).toEqual(mockLabel);
      expect(mockGmailApi.users.labels.get).toHaveBeenCalledTimes(2);
    });
  });

  describe('automatic token refresh callback', () => {
    it('should accept onTokensRefreshed callback in constructor', () => {
      const mockCallback = jest.fn();
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
        onTokensRefreshed: mockCallback,
      };

      gmailClient = new GmailClient(credentials);

      expect(google.auth.OAuth2).toHaveBeenCalledWith(
        credentials.clientId,
        credentials.clientSecret,
        credentials.redirectUri
      );
    });

    it('should set up token refresh event listener when callback provided', () => {
      const mockCallback = jest.fn();
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
        onTokensRefreshed: mockCallback,
      };

      // Add 'on' method to mock auth
      mockAuth.on = jest.fn();

      gmailClient = new GmailClient(credentials);

      // Verify that OAuth2Client.on was called to listen for token events
      expect(mockAuth.on).toHaveBeenCalledWith('tokens', expect.any(Function));
    });

    it('should invoke callback when OAuth2Client emits tokens event', async () => {
      const mockCallback = jest.fn();
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
        onTokensRefreshed: mockCallback,
      };

      // Setup mock auth with event emitter capability
      // Intentionally using `any` for tokens parameter - OAuth2 token structure is test-only concern
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let tokensEventHandler: ((tokens: any) => void) | undefined;
      // Intentionally using `any` for handler parameter - EventEmitter handler type is generic
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      mockAuth.on = jest.fn((event: string, handler: any) => {
        if (event === 'tokens') {
          tokensEventHandler = handler;
        }
      });

      gmailClient = new GmailClient(credentials);

      // Simulate OAuth2Client emitting tokens event (happens on auto-refresh)
      const refreshedTokens = {
        access_token: 'new-access-token',
        refresh_token: 'refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      expect(tokensEventHandler).toBeDefined();
      tokensEventHandler!(refreshedTokens);

      // Verify callback was invoked with refreshed tokens
      expect(mockCallback).toHaveBeenCalledWith(refreshedTokens);
    });

    it('should work without callback (callback is optional)', () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };

      // Should not throw when callback is not provided
      expect(() => new GmailClient(credentials)).not.toThrow();
    });

    it('should handle async callbacks', async () => {
      const mockAsyncCallback = jest.fn().mockResolvedValue(undefined);
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
        onTokensRefreshed: mockAsyncCallback,
      };

      // Intentionally using `any` for tokens parameter - OAuth2 token structure is test-only concern
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let tokensEventHandler: ((tokens: any) => void) | undefined;
      // Intentionally using `any` for handler parameter - EventEmitter handler type is generic
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      mockAuth.on = jest.fn((event: string, handler: any) => {
        if (event === 'tokens') {
          tokensEventHandler = handler;
        }
      });

      gmailClient = new GmailClient(credentials);

      const refreshedTokens = {
        access_token: 'new-access-token',
        expiry_date: Date.now() + 3600000,
      };

      tokensEventHandler!(refreshedTokens);

      // Verify async callback was invoked
      expect(mockAsyncCallback).toHaveBeenCalledWith(refreshedTokens);
    });
  });

  describe('cleanup', () => {
    it('should cleanup resources on dispose', async () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);

      // Dispose should not throw
      await expect(gmailClient.dispose()).resolves.not.toThrow();
    });
  });
});

