/**
 * Unit tests for Gmail API client with authentication
 *
 * @packageDocumentation
 */

/* eslint-disable @typescript-eslint/no-explicit-any */

import { GmailClient } from '../../src/gmail/gmail-client';
import { gmail_v1, google } from 'googleapis';

// Mock the googleapis module
jest.mock('googleapis');

describe('GmailClient', () => {
  let gmailClient: GmailClient;
  let mockGmailApi: jest.Mocked<gmail_v1.Gmail>;
  // Intentionally using `any` for OAuth2Client mock:
  // - OAuth2Client from google-auth-library has complex nested types with 40+ methods/properties
  // - We only need to mock the subset used in tests (credentials, setCredentials, getAccessToken, etc.)
  // - Proper typing would require importing OAuth2Client type AND creating complex mock return types
  let mockAuth: any; // eslint-disable-line @typescript-eslint/no-explicit-any

  beforeEach(() => {
    // Reset all mocks before each test
    jest.clearAllMocks();

    // Create mock Gmail API instance
    mockGmailApi = {
      users: {
        getProfile: jest.fn(),
        messages: {
          list: jest.fn(),
          get: jest.fn(),
        },
      },
    } as any;

    // Create mock OAuth2 client with all required methods
    mockAuth = {
      credentials: {},
      // Intentionally using `any` for credentials parameter - OAuth2 Credentials type is complex
      setCredentials: jest.fn((creds: any) => {
        // eslint-disable-line @typescript-eslint/no-explicit-any
        mockAuth.credentials = creds;
      }),
      getAccessToken: jest.fn(),
      refreshAccessToken: jest.fn(),
      getToken: jest.fn(),
      generateAuthUrl: jest.fn(() => 'https://accounts.google.com/o/oauth2/v2/auth?...'),
      on: jest.fn(), // Event listener for automatic token refresh
    };

    // Mock google.auth.OAuth2 constructor
    (google.auth.OAuth2 as any) = jest.fn(() => mockAuth);

    // Mock google.gmail to return our mock API
    (google.gmail as any) = jest.fn(() => mockGmailApi);
  });

  describe('constructor and initialization', () => {
    it('should create GmailClient with OAuth2 credentials', () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };

      gmailClient = new GmailClient(credentials);

      expect(google.auth.OAuth2).toHaveBeenCalledWith(
        credentials.clientId,
        credentials.clientSecret,
        credentials.redirectUri
      );
    });

    it('should throw error if credentials are missing required fields', () => {
      const invalidCredentials = {
        clientId: 'test-client-id',
        // Missing clientSecret and redirectUri
      } as any;

      expect(() => new GmailClient(invalidCredentials)).toThrow();
    });

    it('should load credentials from environment variables if not provided', () => {
      // Set environment variables
      process.env.GMAIL_CLIENT_ID = 'env-client-id';
      process.env.GMAIL_CLIENT_SECRET = 'env-client-secret';
      process.env.GMAIL_REDIRECT_URI = 'http://localhost:3000/callback';

      gmailClient = new GmailClient();

      expect(google.auth.OAuth2).toHaveBeenCalledWith(
        'env-client-id',
        'env-client-secret',
        'http://localhost:3000/callback'
      );

      // Cleanup
      delete process.env.GMAIL_CLIENT_ID;
      delete process.env.GMAIL_CLIENT_SECRET;
      delete process.env.GMAIL_REDIRECT_URI;
    });

    it('should throw error if environment variables are not set and credentials not provided', () => {
      // Ensure env vars are not set
      delete process.env.GMAIL_CLIENT_ID;
      delete process.env.GMAIL_CLIENT_SECRET;
      delete process.env.GMAIL_REDIRECT_URI;

      expect(() => new GmailClient()).toThrow('Gmail OAuth2 credentials not provided');
    });
  });

  describe('authentication', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should set access token and refresh token', async () => {
      const tokens = {
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() + 3600000, // 1 hour from now
      };

      await gmailClient.setTokens(tokens);

      expect(mockAuth.setCredentials).toHaveBeenCalledWith(tokens);
    });

    it('should generate authorization URL with correct scopes', () => {
      const authUrl = gmailClient.getAuthorizationUrl();

      expect(authUrl).toBeDefined();
      expect(typeof authUrl).toBe('string');
    });

    it('should exchange authorization code for tokens', async () => {
      const code = 'test-authorization-code';
      const mockTokens = {
        access_token: 'new-access-token',
        refresh_token: 'new-refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      mockAuth.getToken = jest.fn().mockResolvedValue({ tokens: mockTokens });

      const tokens = await gmailClient.exchangeCodeForTokens(code);

      expect(mockAuth.getToken).toHaveBeenCalledWith(code);
      expect(tokens).toEqual(mockTokens);
      expect(mockAuth.setCredentials).toHaveBeenCalledWith(mockTokens);
    });

    it('should handle token exchange errors', async () => {
      const code = 'invalid-code';
      const errorMessage = 'Invalid authorization code';

      mockAuth.getToken = jest.fn().mockRejectedValue(new Error(errorMessage));

