    it('should handle async callbacks', async () => {
      const mockAsyncCallback = jest.fn().mockResolvedValue(undefined);
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
        onTokensRefreshed: mockAsyncCallback,
      };

      // Intentionally using `any` for tokens parameter - OAuth2 token structure is test-only concern
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      let tokensEventHandler: ((tokens: any) => void) | undefined;
      // Intentionally using `any` for handler parameter - EventEmitter handler type is generic
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      mockAuth.on = jest.fn((event: string, handler: any) => {
        if (event === 'tokens') {
          tokensEventHandler = handler;
        }
      });

      gmailClient = new GmailClient(credentials);

      const refreshedTokens = {
        access_token: 'new-access-token',
        expiry_date: Date.now() + 3600000,
      };

      tokensEventHandler!(refreshedTokens);

      // Verify async callback was invoked
      expect(mockAsyncCallback).toHaveBeenCalledWith(refreshedTokens);
    });
  });

  describe('cleanup', () => {
    it('should cleanup resources on dispose', async () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);

      // Dispose should not throw
      await expect(gmailClient.dispose()).resolves.not.toThrow();
    });
  });
});

