/**
 * Unit tests for Gmail API client with authentication
 *
 * @packageDocumentation
 */

/* eslint-disable @typescript-eslint/no-explicit-any */

import { GmailClient } from '../../src/gmail/gmail-client';
import { gmail_v1, google } from 'googleapis';

// Mock the googleapis module
jest.mock('googleapis');

describe('GmailClient', () => {
  let gmailClient: GmailClient;
  let mockGmailApi: jest.Mocked<gmail_v1.Gmail>;
  // Intentionally using `any` for OAuth2Client mock:
  // - OAuth2Client from google-auth-library has complex nested types with 40+ methods/properties
  // - We only need to mock the subset used in tests (credentials, setCredentials, getAccessToken, etc.)
  // - Proper typing would require importing OAuth2Client type AND creating complex mock return types
  let mockAuth: any; // eslint-disable-line @typescript-eslint/no-explicit-any

  beforeEach(() => {
    // Reset all mocks before each test
    jest.clearAllMocks();

    // Create mock Gmail API instance
    mockGmailApi = {
      users: {
        getProfile: jest.fn(),
        messages: {
          list: jest.fn(),
          get: jest.fn(),
        },
      },
    } as any;

    // Create mock OAuth2 client with all required methods
    mockAuth = {
      credentials: {},
      // Intentionally using `any` for credentials parameter - OAuth2 Credentials type is complex
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      setCredentials: jest.fn((creds: any) => {
        mockAuth.credentials = creds;
      }),
      getAccessToken: jest.fn(),
      refreshAccessToken: jest.fn(),
      getToken: jest.fn(),
      generateAuthUrl: jest.fn(() => 'https://accounts.google.com/o/oauth2/v2/auth?...'),
      on: jest.fn(), // Event listener for automatic token refresh
    };

    // Mock google.auth.OAuth2 constructor
    (google.auth.OAuth2 as any) = jest.fn(() => mockAuth);

    // Mock google.gmail to return our mock API
    (google.gmail as any) = jest.fn(() => mockGmailApi);
  });

  describe('constructor and initialization', () => {
    it('should create GmailClient with OAuth2 credentials', () => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };

      gmailClient = new GmailClient(credentials);

      expect(google.auth.OAuth2).toHaveBeenCalledWith(
        credentials.clientId,
        credentials.clientSecret,
        credentials.redirectUri
      );
    });

    it('should throw error if credentials are missing required fields', () => {
      const invalidCredentials = {
        clientId: 'test-client-id',
        // Missing clientSecret and redirectUri
      } as any;

      expect(() => new GmailClient(invalidCredentials)).toThrow();
    });

    it('should load credentials from environment variables if not provided', () => {
      // Set environment variables
      process.env.GMAIL_CLIENT_ID = 'env-client-id';
      process.env.GMAIL_CLIENT_SECRET = 'env-client-secret';
      process.env.GMAIL_REDIRECT_URI = 'http://localhost:3000/callback';

      gmailClient = new GmailClient();

      expect(google.auth.OAuth2).toHaveBeenCalledWith(
        'env-client-id',
        'env-client-secret',
        'http://localhost:3000/callback'
      );

      // Cleanup
      delete process.env.GMAIL_CLIENT_ID;
      delete process.env.GMAIL_CLIENT_SECRET;
      delete process.env.GMAIL_REDIRECT_URI;
    });

    it('should throw error if environment variables are not set and credentials not provided', () => {
      // Ensure env vars are not set
      delete process.env.GMAIL_CLIENT_ID;
      delete process.env.GMAIL_CLIENT_SECRET;
      delete process.env.GMAIL_REDIRECT_URI;

      expect(() => new GmailClient()).toThrow('Gmail OAuth2 credentials not provided');
    });
  });

  describe('authentication', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should set access token and refresh token', async () => {
      const tokens = {
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() + 3600000, // 1 hour from now
      };

      await gmailClient.setTokens(tokens);

      expect(mockAuth.setCredentials).toHaveBeenCalledWith(tokens);
    });

    it('should generate authorization URL with correct scopes', () => {
      const authUrl = gmailClient.getAuthorizationUrl();

      expect(authUrl).toBeDefined();
      expect(typeof authUrl).toBe('string');
    });

    it('should exchange authorization code for tokens', async () => {
      const code = 'test-authorization-code';
      const mockTokens = {
        access_token: 'new-access-token',
        refresh_token: 'new-refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      mockAuth.getToken = jest.fn().mockResolvedValue({ tokens: mockTokens });

      const tokens = await gmailClient.exchangeCodeForTokens(code);

      expect(mockAuth.getToken).toHaveBeenCalledWith(code);
      expect(tokens).toEqual(mockTokens);
      expect(mockAuth.setCredentials).toHaveBeenCalledWith(mockTokens);
    });

    it('should handle token exchange errors', async () => {
      const code = 'invalid-code';
      const errorMessage = 'Invalid authorization code';

      mockAuth.getToken = jest.fn().mockRejectedValue(new Error(errorMessage));

      await expect(gmailClient.exchangeCodeForTokens(code)).rejects.toThrow(errorMessage);
    });

    it('should refresh expired access token', async () => {
      const mockRefreshedTokens = {
        access_token: 'refreshed-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      mockAuth.refreshAccessToken = jest.fn().mockResolvedValue({
        credentials: mockRefreshedTokens,
      });

      const tokens = await gmailClient.refreshTokens();

      expect(mockAuth.refreshAccessToken).toHaveBeenCalled();
      expect(tokens).toEqual(mockRefreshedTokens);
      expect(mockAuth.setCredentials).toHaveBeenCalledWith(mockRefreshedTokens);
    });

    it('should handle token refresh errors', async () => {
      const errorMessage = 'Refresh token expired';

      mockAuth.refreshAccessToken = jest.fn().mockRejectedValue(new Error(errorMessage));

      await expect(gmailClient.refreshTokens()).rejects.toThrow(errorMessage);
    });
  });

  describe('user profile', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);

      // Set tokens to simulate authenticated state
      mockAuth.setCredentials({
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
      });
    });

    it('should fetch user profile successfully', async () => {
      const mockProfile = {
        emailAddress: 'test@example.com',
        messagesTotal: 1000,
        threadsTotal: 500,
        historyId: '12345',
      };

      mockGmailApi.users.getProfile = jest.fn().mockResolvedValue({
        data: mockProfile,
      });

      const profile = await gmailClient.getUserProfile();

      expect(mockGmailApi.users.getProfile).toHaveBeenCalledWith({
        userId: 'me',
      });
      expect(profile).toEqual(mockProfile);
    });

    it('should handle API errors when fetching profile', async () => {
      const errorMessage = 'Unauthorized';

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(new Error(errorMessage));

      await expect(gmailClient.getUserProfile()).rejects.toThrow(errorMessage);
    });
  });

  describe('authentication status', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should return authentication status with valid tokens', async () => {
      const mockTokens = {
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() + 3600000,
      };

      await gmailClient.setTokens(mockTokens);

      const mockProfile = {
        emailAddress: 'test@example.com',
      };

      mockGmailApi.users.getProfile = jest.fn().mockResolvedValue({
        data: mockProfile,
      });

      const status = await gmailClient.getAuthStatus();

      expect(status.authenticated).toBe(true);
      expect(status.tokenValid).toBe(true);
      expect(status.userEmail).toBe('test@example.com');
      expect(status.tokenExpiresAt).toBeDefined();
      expect(status.scopes).toBeDefined();
    });

    it('should return authentication status with expired tokens', async () => {
      const mockTokens = {
        access_token: 'test-access-token',
        refresh_token: 'test-refresh-token',
        expiry_date: Date.now() - 1000, // Expired 1 second ago
      };

      await gmailClient.setTokens(mockTokens);

      const status = await gmailClient.getAuthStatus();

      expect(status.authenticated).toBe(true);
      expect(status.tokenValid).toBe(false);
    });

    it('should return unauthenticated status when no tokens set', async () => {
      const status = await gmailClient.getAuthStatus();

      expect(status.authenticated).toBe(false);
      expect(status.tokenValid).toBe(false);
      expect(status.userEmail).toBeUndefined();
    });
  });

  describe('rate limiting', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should handle rate limit errors with retry', async () => {
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
        errors: [
          {
            domain: 'usageLimits',
            reason: 'rateLimitExceeded',
          },
        ],
      };

      // First call fails with rate limit, second succeeds
      mockGmailApi.users.getProfile = jest
        .fn()
        .mockRejectedValueOnce(rateLimitError)
        .mockResolvedValueOnce({
          data: { emailAddress: 'test@example.com' },
        });

      const profile = await gmailClient.getUserProfile({ retryOnRateLimit: true });

      expect(profile.emailAddress).toBe('test@example.com');
      expect(mockGmailApi.users.getProfile).toHaveBeenCalledTimes(2);
    });

    it('should not retry on non-rate-limit errors', async () => {
      const otherError = new Error('Other error');

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(otherError);

      await expect(gmailClient.getUserProfile({ retryOnRateLimit: true })).rejects.toThrow('Other error');
      expect(mockGmailApi.users.getProfile).toHaveBeenCalledTimes(1);
    });

    it('should respect max retry attempts', async () => {
      const rateLimitError = {
        code: 429,
        message: 'Rate limit exceeded',
      };

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(rateLimitError);

      await expect(gmailClient.getUserProfile({ retryOnRateLimit: true, maxRetries: 3 })).rejects.toMatchObject({
        code: 429,
        message: 'Rate limit exceeded',
      });

      expect(mockGmailApi.users.getProfile).toHaveBeenCalledTimes(4); // Initial + 3 retries
    });
  });

  describe('error handling', () => {
    beforeEach(() => {
      const credentials = {
        clientId: 'test-client-id',
        clientSecret: 'test-client-secret',
        redirectUri: 'http://localhost:3000/oauth2callback',
      };
      gmailClient = new GmailClient(credentials);
    });

    it('should handle network errors', async () => {
      const networkError = new Error('ECONNREFUSED');

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(networkError);

      await expect(gmailClient.getUserProfile()).rejects.toThrow('ECONNREFUSED');
    });

    it('should handle authentication errors', async () => {
      const authError = {
        code: 401,
        message: 'Invalid credentials',
      };

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(authError);

      await expect(gmailClient.getUserProfile()).rejects.toMatchObject({
        code: 401,
        message: 'Invalid credentials',
      });
    });

    it('should handle permission errors', async () => {
      const permissionError = {
        code: 403,
        message: 'Insufficient permissions',
      };

      mockGmailApi.users.getProfile = jest.fn().mockRejectedValue(permissionError);

      await expect(gmailClient.getUserProfile()).rejects.toMatchObject({
