/**
 * Unit tests for hierarchical environment loader
 *
 * Tests loading .env files from current working directory up to filesystem root,
 * with child directories overriding parent directories.
 *
 * @packageDocumentation
 */

/* eslint-disable @typescript-eslint/no-explicit-any */

import * as path from 'path';
import * as fs from 'fs';
import { loadEnvironment, clearEnvironment } from '../../src/config/env';

// Mock fs and path modules
jest.mock('fs');
jest.mock('path');

describe('loadEnvironment', () => {
  const mockFs = fs as jest.Mocked<typeof fs>;
  const mockPath = path as jest.Mocked<typeof path>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Clear any previously loaded environment variables
    clearEnvironment();

    // Reset process.env to known state
    delete process.env.TEST_VAR;
    delete process.env.PARENT_VAR;
    delete process.env.CHILD_VAR;
    delete process.env.OVERRIDE_VAR;
  });

  describe('single directory', () => {
    it('should load .env from current working directory', () => {
      const cwd = '/app/packages/email-processor';
      const envPath = path.join(cwd, '.env');

      mockPath.join.mockReturnValue(envPath);
      mockPath.dirname.mockReturnValue(cwd);
      mockPath.parse.mockReturnValue({
        root: '/',
        dir: '/app/packages',
        base: 'email-processor',
        ext: '',
        name: 'email-processor',
      });

      mockFs.existsSync.mockImplementation((filePath) => {
        return filePath === envPath;
      });

      mockFs.readFileSync.mockImplementation((filePath) => {
        if (filePath === envPath) {
          return 'TEST_VAR=from_current\n';
        }
        throw new Error('File not found');
      });

      loadEnvironment(cwd);

      expect(process.env.TEST_VAR).toBe('from_current');
    });

    it('should handle missing .env file without error', () => {
      const cwd = '/app/packages/email-processor';

      mockPath.join.mockReturnValue(path.join(cwd, '.env'));
      mockPath.dirname.mockReturnValue(cwd);
      mockPath.parse.mockReturnValue({
        root: '/',
        dir: '/app/packages',
        base: 'email-processor',
        ext: '',
        name: 'email-processor',
      });

      mockFs.existsSync.mockReturnValue(false);

      expect(() => loadEnvironment(cwd)).not.toThrow();
    });
  });

  describe('hierarchical loading', () => {
    it('should load .env files from child to parent directories', () => {
      const cwd = '/app/packages/email-processor';
      const parentDir = '/app/packages';
      const rootDir = '/app';
      const fsRoot = '/';

      // Setup directory hierarchy mocks
      mockPath.dirname
        .mockReturnValueOnce(parentDir) // First call: /app/packages
        .mockReturnValueOnce(rootDir) // Second call: /app
        .mockReturnValueOnce(fsRoot) // Third call: /
        .mockReturnValueOnce(fsRoot); // Fourth call: / (stop condition)

      mockPath.parse
        .mockReturnValueOnce({
          root: '/',
          dir: '/app/packages',
          base: 'email-processor',
          ext: '',
          name: 'email-processor',
        })
        .mockReturnValueOnce({ root: '/', dir: '/app', base: 'packages', ext: '', name: 'packages' })
        .mockReturnValueOnce({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' })
        .mockReturnValueOnce({ root: '/', dir: '/', base: '', ext: '', name: '' });

      mockPath.join.mockImplementation((dir, file) => `${dir}/${file}`);

      // Mock .env files at different levels
      mockFs.existsSync.mockImplementation((filePath) => {
        return filePath === `${cwd}/.env` || filePath === `${parentDir}/.env` || filePath === `${rootDir}/.env`;
      });

      mockFs.readFileSync.mockImplementation((filePath) => {
        if (filePath === `${rootDir}/.env`) {
          return 'PARENT_VAR=from_root\nOVERRIDE_VAR=parent_value\n';
        }
        if (filePath === `${parentDir}/.env`) {
          return 'PARENT_VAR=from_packages\n';
        }
        if (filePath === `${cwd}/.env`) {
          return 'CHILD_VAR=from_child\nOVERRIDE_VAR=child_value\n';
        }
        throw new Error('File not found');
      });

      loadEnvironment(cwd);

      expect(process.env.PARENT_VAR).toBe('from_packages'); // From middle level
      expect(process.env.CHILD_VAR).toBe('from_child'); // From current level
      expect(process.env.OVERRIDE_VAR).toBe('child_value'); // Child overrides parent
    });

    it('should stop at filesystem root', () => {
      const cwd = '/app';
      const fsRoot = '/';

      mockPath.dirname.mockReturnValueOnce(fsRoot).mockReturnValueOnce(fsRoot);

      mockPath.parse
        .mockReturnValueOnce({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' })
        .mockReturnValueOnce({ root: '/', dir: '/', base: '', ext: '', name: '' });

      mockPath.join.mockImplementation((dir, file) => `${dir}${dir === '/' ? '' : '/'}${file}`);

      mockFs.existsSync.mockImplementation((filePath) => {
        return filePath === `${cwd}/.env`;
      });

      mockFs.readFileSync.mockImplementation((filePath) => {
        if (filePath === `${cwd}/.env`) {
          return 'TEST_VAR=value\n';
        }
        throw new Error('File not found');
      });

      loadEnvironment(cwd);

      expect(process.env.TEST_VAR).toBe('value');

      // Should have checked current dir and root, but stopped there
      expect(mockPath.dirname).toHaveBeenCalledTimes(2);
    });

    it('should handle Windows filesystem root (C:\\)', () => {
      const cwd = 'C:\\app\\packages\\email-processor';
      const parentDir = 'C:\\app\\packages';
      const rootDir = 'C:\\app';
      const fsRoot = 'C:\\';

      mockPath.dirname
        .mockReturnValueOnce(parentDir)
        .mockReturnValueOnce(rootDir)
        .mockReturnValueOnce(fsRoot)
        .mockReturnValueOnce(fsRoot);

      mockPath.parse
        .mockReturnValueOnce({
          root: 'C:\\',
          dir: 'C:\\app\\packages',
          base: 'email-processor',
          ext: '',
          name: 'email-processor',
        })
        .mockReturnValueOnce({ root: 'C:\\', dir: 'C:\\app', base: 'packages', ext: '', name: 'packages' })
        .mockReturnValueOnce({ root: 'C:\\', dir: 'C:\\', base: 'app', ext: '', name: 'app' })
        .mockReturnValueOnce({ root: 'C:\\', dir: 'C:\\', base: '', ext: '', name: '' });

      mockPath.join.mockImplementation((dir, file) => `${dir}\\${file}`);

      mockFs.existsSync.mockImplementation((filePath) => {
        return filePath === `${cwd}\\.env`;
      });

      mockFs.readFileSync.mockImplementation((filePath) => {
        if (filePath === `${cwd}\\.env`) {
          return 'TEST_VAR=windows_value\n';
        }
        throw new Error('File not found');
      });

      loadEnvironment(cwd);

      expect(process.env.TEST_VAR).toBe('windows_value');
    });
  });

  describe('error handling', () => {
    it('should handle permissions errors gracefully', () => {
      const cwd = '/app/packages/email-processor';
      const parentDir = '/app/packages';

      mockPath.dirname.mockReturnValueOnce(parentDir);
      mockPath.parse.mockReturnValueOnce({
        root: '/',
        dir: '/app/packages',
        base: 'email-processor',
        ext: '',
        name: 'email-processor',
      });
      mockPath.join.mockImplementation((dir, file) => `${dir}/${file}`);

      mockFs.existsSync.mockImplementation((filePath) => {
        if (filePath === `${cwd}/.env`) return true;
        if (filePath === `${parentDir}/.env`) return true;
        return false;
      });

      mockFs.readFileSync.mockImplementation((filePath) => {
        if (filePath === `${cwd}/.env`) {
          return 'CHILD_VAR=value\n';
        }
        if (filePath === `${parentDir}/.env`) {
          // Intentionally using `any` to create Error with custom `code` property
          // Node.js fs errors include a `code` property, but TypeScript's Error type doesn't
          // This simulates a realistic EACCES file system error for testing
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const error: any = new Error('EACCES: permission denied');
          error.code = 'EACCES';
          throw error;
        }
        throw new Error('File not found');
      });

      // Should not throw, but should stop walking up
      expect(() => loadEnvironment(cwd)).not.toThrow();

      // Should have loaded from current directory before hitting permissions error
      expect(process.env.CHILD_VAR).toBe('value');
    });

    it('should handle file read errors for non-permissions issues', () => {
      const cwd = '/app/packages/email-processor';

      mockPath.dirname.mockReturnValueOnce('/app/packages');
      mockPath.parse.mockReturnValueOnce({
        root: '/',
        dir: '/app/packages',
        base: 'email-processor',
        ext: '',
        name: 'email-processor',
      });
      mockPath.join.mockImplementation((dir, file) => `${dir}/${file}`);

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockImplementation(() => {
        throw new Error('Unexpected error');
      });

      // Should not throw even on unexpected errors
      expect(() => loadEnvironment(cwd)).not.toThrow();
    });
  });

  describe('environment variable parsing', () => {
    it('should parse simple key=value pairs', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('SIMPLE_VAR=simple_value\n');

      loadEnvironment(cwd);

      expect(process.env.SIMPLE_VAR).toBe('simple_value');
    });

    it('should handle quoted values', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('QUOTED_VAR="quoted value"\nSINGLE_VAR=\'single value\'\n');

      loadEnvironment(cwd);

      expect(process.env.QUOTED_VAR).toBe('quoted value');
      expect(process.env.SINGLE_VAR).toBe('single value');
    });

    it('should handle empty lines and comments', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue(`
# This is a comment
VALID_VAR=value

# Another comment
ANOTHER_VAR=another_value
      `);

      loadEnvironment(cwd);

      expect(process.env.VALID_VAR).toBe('value');
      expect(process.env.ANOTHER_VAR).toBe('another_value');
    });

    it('should handle values with equals signs', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('CONNECTION_STRING=postgresql://user:pass@localhost/db?key=value\n');

      loadEnvironment(cwd);

      expect(process.env.CONNECTION_STRING).toBe('postgresql://user:pass@localhost/db?key=value');
    });
  });

  describe('clearEnvironment', () => {
    it('should clear all loaded environment variables', () => {
      const cwd = '/app';

      mockPath.dirname.mockReturnValue('/');
      mockPath.parse.mockReturnValue({ root: '/', dir: '/', base: 'app', ext: '', name: 'app' });
      mockPath.join.mockReturnValue('/app/.env');

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('CLEAR_TEST_VAR=value\n');

      loadEnvironment(cwd);
      expect(process.env.CLEAR_TEST_VAR).toBe('value');

      clearEnvironment();
      expect(process.env.CLEAR_TEST_VAR).toBeUndefined();
    });
  });

  describe('default behavior', () => {
    it('should use process.cwd() when no directory specified', () => {
      const originalCwd = process.cwd();
      const mockCwd = '/app/packages/email-processor';

      // Mock process.cwd()
      jest.spyOn(process, 'cwd').mockReturnValue(mockCwd);

      mockPath.dirname.mockReturnValue('/app/packages');
      mockPath.parse.mockReturnValue({
        root: '/',
        dir: '/app/packages',
        base: 'email-processor',
        ext: '',
        name: 'email-processor',
      });
      mockPath.join.mockReturnValue(`${mockCwd}/.env`);

      mockFs.existsSync.mockReturnValue(true);
      mockFs.readFileSync.mockReturnValue('DEFAULT_VAR=default_value\n');

      loadEnvironment(); // No argument - should use process.cwd()

      expect(process.env.DEFAULT_VAR).toBe('default_value');

      // Restore original cwd
      jest.spyOn(process, 'cwd').mockReturnValue(originalCwd);
    });
  });
});

