/**
 * Unit tests for ClassificationRepository (T043 - TDD Approach)
 *
 * Tests classification results persistence with explainability trace storage,
 * score breakdown persistence, and audit trail integrity.
 *
 * Test Strategy:
 * - Mock Prisma client for unit testing
 * - Test session lifecycle (create, update, complete)
 * - Test classification result persistence with nested data
 * - Test multi-label support
 * - Test attribute context and domain signal persistence
 * - Test error handling and transaction rollback
 */

import { ClassificationRepository } from '../../src/persistence/classification-repository';
import { PrismaClient } from '@prisma/client';
import { ClassificationResult, ClassificationSession } from '@gmail-automation/classification-engine';

// Mock Prisma Client
jest.mock('@prisma/client', () => {
  // Intentionally using `any` for Prisma mock:
  // - Prisma generates massive nested types specific to schema (PrismaClient type is 1000+ lines)
  // - We only need to mock the subset of methods used in tests (multiple tables with create/find methods)
  // - Attempting to type this correctly would require importing @prisma/client types AND creating
  //   mock return types for each method, adding significant test complexity for no runtime benefit
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const mockPrismaClient: any = {
    classificationSession: {
      create: jest.fn(),
      update: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
    },
    classificationStage: {
      create: jest.fn(),
      createMany: jest.fn(),
      findMany: jest.fn(),
    },
    stageCategoryEval: {
      createMany: jest.fn(),
    },
    sessionCategory: {
      createMany: jest.fn(),
    },
    detectedAttribute: {
      createMany: jest.fn(),
    },
    domainSignalResolution: {
      createMany: jest.fn(),
    },
    extractedFeature: {
      createMany: jest.fn(),
    },
    category: {
      findMany: jest.fn(),
    },
    $transaction: jest.fn((callback) => callback(mockPrismaClient)),
    $disconnect: jest.fn(),
  };

  // Mock Prisma Decimal class
  class MockDecimal {
    value: number;
    constructor(value: number | string) {
      this.value = typeof value === 'string' ? parseFloat(value) : value;
    }
    toString() {
      return this.value.toString();
    }
    toNumber() {
      return this.value;
    }
  }

  return {
    PrismaClient: jest.fn(() => mockPrismaClient),
    Prisma: {
      Decimal: MockDecimal,
    },
  };
});

describe('ClassificationRepository', () => {
  let repository: ClassificationRepository;
  let mockPrisma: jest.Mocked<PrismaClient>;

  beforeEach(() => {
    // Reset all mocks before each test
    jest.clearAllMocks();

    // Create repository with mocked Prisma
    repository = new ClassificationRepository();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    mockPrisma = (repository as any).prisma;

    // Mock category cache data for all tests
    (mockPrisma.category.findMany as jest.Mock).mockResolvedValue([
      { code: 'financial', categoryId: 1 },
      { code: 'receipt', categoryId: 2 },
      { code: 'bill', categoryId: 3 },
      { code: 'actionable', categoryId: 4 },
      { code: 'newsletter', categoryId: 5 },
      { code: 'ecommerce', categoryId: 6 },
    ]);

    // Mock classificationStage.findMany for AI feature extraction (Agent 3's addition)
    (mockPrisma.classificationStage.findMany as jest.Mock).mockResolvedValue([
      { stageId: BigInt(1), stageOrder: 1 },
      { stageId: BigInt(2), stageOrder: 2 },
      { stageId: BigInt(3), stageOrder: 3 },
      { stageId: BigInt(4), stageOrder: 4 },
      { stageId: BigInt(5), stageOrder: 5 },
      { stageId: BigInt(6), stageOrder: 6 },
      { stageId: BigInt(7), stageOrder: 7 },
      { stageId: BigInt(8), stageOrder: 8 },
      { stageId: BigInt(9), stageOrder: 9 },
      { stageId: BigInt(10), stageOrder: 10 },
    ]);
  });

  afterEach(async () => {
    await repository.close();
  });

  describe('Session Management', () => {
    it('should create a new classification session', async () => {
      const session: ClassificationSession = {
        id: 'session-123',
        startedAt: new Date('2025-01-01T10:00:00Z'),
        emailCount: 10,
        successCount: 0,
        errorCount: 0,
        processingMode: 'parallel',
        batchSize: 10,
        performanceMetrics: {
          totalDurationMs: 0,
          avgEmailDurationMs: 0,
          parallelStagesCount: 0,
          databaseBatchOps: 0,
        },
        configVersion: 'v1.0.0',
        configSnapshot: { version: 1 },
        errors: [],
        warnings: [],
      };

      (mockPrisma.classificationSession.create as jest.Mock).mockResolvedValue({
        sessionId: BigInt(1),
        gmailId: 'msg-001',
        pipelineVersion: 'v1.0.0',
        startedAt: session.startedAt,
        completedAt: null,
        finalCategoryCode: null,
        finalConfidence: null,
        finalRationale: null,
        finalKeywords: [],
        finalFeatures: {},
        aiRoutingUsed: false,
        status: 'in_progress',
        triggeredBy: 'system',
      });

      const sessionId = await repository.createSession(session, 'msg-001');

      // Verify session ID is returned as string (safe representation of bigint)
      expect(typeof sessionId).toBe('string');
      expect(sessionId).toBe('1');

      expect(mockPrisma.classificationSession.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          gmailId: 'msg-001',
          pipelineVersion: 'v1.0.0',
          startedAt: session.startedAt,
          status: 'in_progress',
          triggeredBy: 'system',
        }),
      });
    });

    it('should update session on completion', async () => {
      const sessionId = '1'; // Numeric string (from createSession)
      const finalCategoryCode = 'financial';
      const confidence = 0.95;
      const rationale = 'High confidence classification';

      (mockPrisma.classificationSession.update as jest.Mock).mockResolvedValue({
        sessionId: BigInt(1),
        gmailId: 'msg-001',
        pipelineVersion: 'v1.0.0',
        startedAt: new Date(),
        completedAt: new Date(),
        finalCategoryCode: finalCategoryCode,
        finalConfidence: confidence,
        finalRationale: rationale,
        finalKeywords: ['receipt', 'payment'],
        finalFeatures: {},
        aiRoutingUsed: false,
        status: 'completed',
        triggeredBy: 'system',
      });

      await repository.completeSession(sessionId, finalCategoryCode, confidence, rationale);

      expect(mockPrisma.classificationSession.update).toHaveBeenCalledWith({
        where: { sessionId: BigInt(1) },
        data: expect.objectContaining({
          completedAt: expect.any(Date),
          finalCategoryCode: finalCategoryCode,
          finalConfidence: expect.any(Object), // Prisma.Decimal instance
          finalRationale: rationale,
          status: 'completed',
        }),
      });
    });

    it('should handle session not found error gracefully', async () => {
      (mockPrisma.classificationSession.update as jest.Mock).mockRejectedValue(new Error('Session not found'));

      await expect(repository.completeSession('999', 'unknown-category', 0.5, 'test')).rejects.toThrow(
        'Failed to complete session'
      );
    });
  });

  describe('Classification Result Persistence', () => {
    it('should persist classification result with explainability trace', async () => {
      const result: ClassificationResult = {
        id: 'result-123',
        emailId: 'msg-001',
        sessionId: 'session-123',
        primaryCategory: 'financial',
        secondaryCategories: ['receipt'],
        confidence: 0.95,
        explainabilityTrace: {
          sessionId: 'session-123',
          emailId: 'msg-001',
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
          attributeInfluence: [],
          disambiguation: [],
          multiLabelSelection: [],
          aiRouting: undefined,
          stageTimings: { hardAssertions: 10, strongIndicators: 15 },
          parallelExecutionMap: {},
          configurationRefs: {},
          finalDecisionReason: 'High confidence from domain matching',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: 'msg-001',
          categoryScores: {
            financial: {
              baseScore: 0.5,
              hardAssertionBonus: 0.3,
              strongIndicatorScore: 0.1,
              ruleScore: 0.05,
              attributeInfluenceScore: 0.0,
              finalScore: 0.95,
              parallelComputedComponents: [],
              computationDurationMs: 50,
              cacheHits: [],
              scoreAggregationSteps: [],
              cappingApplied: false,
            },
          },
          stageContributions: {},
          disambiguationApplied: [],
          parallelComputationMetrics: {
            totalParallelOperations: 0,
            parallelEfficiencyScore: 0,
            bottleneckStages: [],
            peakMemoryUsageMB: 0,
            averageCpuUtilization: 0,
            concurrentOperationsPeak: 0,
            parallelizableButSequential: [],
            parallelConflicts: [],
          },
        },
        attributeContext: {
          emailId: 'msg-001',
          urgency: 'low',
          domains: ['chase.com'],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
          derivedAttributes: {},
          attributeRelationships: [],
        },
        processedAt: new Date('2025-01-01T10:05:00Z'),
        processingDurationMs: 5000,
        aiRoutingUsed: false,
        batchPosition: 1,
        parallelStageResults: [],
        selectedLabels: [
          {
            category: 'financial',
            subtype: 'receipt',
            confidence: 0.95,
            score: 0.95,
            isPrimary: true,
            labelOrder: 1,
            selectionRationale: 'Domain match + subject keywords',
          },
        ],
        candidateScores: {
          financial: { score: 0.95, confidence: 0.95, decision: 'selected' },
        },
        selectionSummary: {
          totalLabels: 1,
          primaryCategory: 'financial',
          confidenceRange: [0.95, 0.95],
          selectionMethod: 'rule-based',
          needsAi: false,
        },
        needsAiClassification: false,
      };

      // Mock transaction to succeed
      mockPrisma.$transaction.mockImplementation(async (callback) => {
        return callback(mockPrisma);
      });

      (mockPrisma.classificationStage.createMany as jest.Mock).mockResolvedValue({ count: 9 });
      (mockPrisma.stageCategoryEval.createMany as jest.Mock).mockResolvedValue({ count: 6 });
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (mockPrisma as any).sessionCategory.createMany.mockResolvedValue({ count: 1 });
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      (mockPrisma as any).detectedAttribute.createMany.mockResolvedValue({ count: 2 });

      await repository.saveClassificationResult(result, '1');

      // Verify transaction was used
      expect(mockPrisma.$transaction).toHaveBeenCalled();

      // Verify classification stages were created
      expect(mockPrisma.classificationStage.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            sessionId: BigInt(1),
            stageType: expect.any(String),
            stageOrder: expect.any(Number),
          }),
        ]),
      });

      // Verify session categories were created
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      expect((mockPrisma as any).sessionCategory.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            sessionId: BigInt(1),
            isPrimary: true,
          }),
        ]),
      });
    });

    it('should handle multi-label classification results', async () => {
      const result: ClassificationResult = {
        id: 'result-456',
        emailId: 'msg-002',
        sessionId: 'session-456',
        primaryCategory: 'financial',
        secondaryCategories: ['actionable'],
        confidence: 0.85,
        explainabilityTrace: {
          sessionId: 'session-456',
          emailId: 'msg-002',
          hardAssertions: [],
          strongIndicators: [],
          ruleScoring: [],
          attributeDetection: [],
          attributeInfluence: [],
          disambiguation: [],
          multiLabelSelection: [],
          stageTimings: {},
          parallelExecutionMap: {},
          configurationRefs: {},
          finalDecisionReason: 'Multi-label classification',
          alternativeCategories: [],
        },
        scoreBreakdown: {
          emailId: 'msg-002',
          categoryScores: {},
          stageContributions: {},
          disambiguationApplied: [],
          parallelComputationMetrics: {
            totalParallelOperations: 0,
            parallelEfficiencyScore: 0,
            bottleneckStages: [],
            peakMemoryUsageMB: 0,
            averageCpuUtilization: 0,
            concurrentOperationsPeak: 0,
            parallelizableButSequential: [],
            parallelConflicts: [],
          },
        },
        attributeContext: {
          emailId: 'msg-002',
          urgency: 'high',
          domains: [],
          structuralPatterns: [],
          temporalSignals: [],
          detectionMetadata: {},
          influenceApplications: [],
          derivedAttributes: {},
          attributeRelationships: [],
        },
        processedAt: new Date(),
        processingDurationMs: 3000,
        aiRoutingUsed: false,
        batchPosition: 2,
        parallelStageResults: [],
        selectedLabels: [
          {
            category: 'financial',
            subtype: 'bill',
            confidence: 0.85,
            score: 0.85,
            isPrimary: true,
            labelOrder: 1,
            selectionRationale: 'Primary category',
          },
          {
            category: 'actionable',
            subtype: null,
            confidence: 0.75,
            score: 0.75,
            isPrimary: false,
            labelOrder: 2,
            selectionRationale: 'Secondary category',
          },
        ],
        candidateScores: {},
        selectionSummary: {
          totalLabels: 2,
          primaryCategory: 'financial',
          confidenceRange: [0.75, 0.85],
          selectionMethod: 'rule-based',
          needsAi: false,
        },
        needsAiClassification: false,
      };

      mockPrisma.$transaction.mockImplementation(async (callback) => callback(mockPrisma));
      (mockPrisma.classificationStage.createMany as jest.Mock).mockResolvedValue({ count: 9 });
      (mockPrisma.sessionCategory.createMany as jest.Mock).mockResolvedValue({ count: 2 });

      await repository.saveClassificationResult(result, '1');

      // Verify both primary and secondary labels were saved
      expect(mockPrisma.sessionCategory.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({ isPrimary: true, labelOrder: 1 }),
          expect.objectContaining({ isPrimary: false, labelOrder: 2 }),
        ]),
      });
    });

    it('should rollback transaction on error', async () => {
      const result: Partial<ClassificationResult> = {
        id: 'result-error',
        emailId: 'msg-error',
        sessionId: 'session-error',
        primaryCategory: 'test',
        secondaryCategories: [],
        confidence: 0.5,
      };

      // Mock transaction to simulate error
      mockPrisma.$transaction.mockRejectedValue(new Error('Database constraint violation'));

      await expect(repository.saveClassificationResult(result as ClassificationResult, '1')).rejects.toThrow(
        'Failed to save classification result'
      );

      // Verify transaction was attempted
      expect(mockPrisma.$transaction).toHaveBeenCalled();
    });
  });

  describe('Attribute Context Persistence', () => {
    it('should persist detected attributes with influence tracking', async () => {
      const attributeContext = {
        emailId: 'msg-003',
        urgency: 'high' as const,
        domains: ['amazon.com'],
        structuralPatterns: ['order_confirmation'],
        temporalSignals: [],
        detectionMetadata: {
          urgency: {
            detectedAt: new Date(),
            confidence: 0.9,
            detectionMethod: 'rule' as const,
            parallelProcessed: false,
            dependencies: [],
          },
        },
        influenceApplications: [
          {
            targetCategory: 'ecommerce',
            attributeUsed: 'domain:amazon.com',
            roleType: 'CORE' as const,
            scoreImpact: 0.5,
            applicationReason: 'Domain hard assertion',
            appliedDuringParallelExecution: false,
            dependentOnAttributes: [],
            influenceTimestamp: new Date(),
            influenceReliability: 0.95,
            historicalAccuracy: 0.9,
          },
        ],
        derivedAttributes: {},
        attributeRelationships: [],
      };

      (mockPrisma.detectedAttribute.createMany as jest.Mock).mockResolvedValue({ count: 2 });

      await repository.saveAttributeContext(attributeContext, '1');

      expect(mockPrisma.detectedAttribute.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            sessionId: BigInt(1),
            attributeName: expect.any(String),
            detectionMethod: expect.any(String),
            influenceRole: expect.any(String),
          }),
        ]),
      });
    });

    it('should handle empty attribute context gracefully', async () => {
      const emptyContext = {
        emailId: 'msg-004',
        urgency: 'low' as const,
        domains: [],
        structuralPatterns: [],
        temporalSignals: [],
        detectionMetadata: {},
        influenceApplications: [],
        derivedAttributes: {},
        attributeRelationships: [],
      };

      (mockPrisma.detectedAttribute.createMany as jest.Mock).mockResolvedValue({ count: 0 });

      await repository.saveAttributeContext(emptyContext, '1');

      // Should still attempt to save (even if empty)
      expect(mockPrisma.detectedAttribute.createMany).toHaveBeenCalled();
    });
  });

  describe('Domain Signal Resolutions', () => {
    it('should persist domain signal resolutions', async () => {
      const domainSignals = [
        {
          domain: 'chase.com',
          signalType: 'hard_assertion' as const,
          matchedCategoryId: 10,
          confidenceLevel: 'high',
          domainType: 'financial',
        },
        {
          domain: 'newsletter.example.com',
          signalType: 'strong_indicator' as const,
          matchedCategoryId: 20,
          confidenceLevel: 'medium',
          domainType: 'newsletter',
        },
      ];

      (mockPrisma.domainSignalResolution.createMany as jest.Mock).mockResolvedValue({ count: 2 });

      await repository.saveDomainSignals(domainSignals, '1');

      expect(mockPrisma.domainSignalResolution.createMany).toHaveBeenCalledWith({
        data: expect.arrayContaining([
          expect.objectContaining({
            sessionId: BigInt(1),
